import { Collectable } from './_base';

export type Resource = Collectable & {};

export enum ResourceType {
  wood = 'wood',
  firewood = 'firewood',
  fiber = 'fiber',
  resin = 'resin',
  oil = 'oil',
  seeds = 'seeds',
  thatch = 'thatch',
  tinder = 'tinder',
}

export const RESOURCES = {
  [ResourceType.wood]: {
    name: `Drewno`,
    weight: 9,
  },
  [ResourceType.firewood]: {
    name: `Drewno opałowe`,
    weight: 0,
  },
  [ResourceType.fiber]: {
    name: `Włókno`,
    weight: 0.5,
  },
  [ResourceType.resin]: {
    name: `Żywica`,
    weight: 0.35,
  },
  [ResourceType.oil]: {
    name: `Olej`,
    weight: 0.5,
  },
  [ResourceType.seeds]: {
    name: `Nasiona`,
    weight: 0.02,
  },
  [ResourceType.thatch]: {
    name: `Słoma`,
    weight: 0.6,
  },
  [ResourceType.tinder]: {
    name: `Podpałka`,
    weight: 0.05,
  },
} as const satisfies Record<ResourceType, Resource>;

export const getResource = (type: ResourceType): Resource => RESOURCES[type];
