export enum BiomeType {
  sea = 'sea',
  inlandWaters = 'inlandWaters',
  waterfront = 'waterfront',
  grass = 'grass',
  forest = 'forest',
  mountain = 'mountain',
  snow = 'snow',
}

export interface Biome {
  threshold: number;
  image: string;
  plantDensity: number;
  colorFrom: [number, number, number];
  colorTo: [number, number, number];
}

export const BIOMES = {
  [BiomeType.sea]: {
    threshold: 0.003,
    image: 'assets/images/textures/water.jpg',
    plantDensity: 0.05,
    colorFrom: [28, 78, 75],
    colorTo: [47, 131, 126],
  },
  [BiomeType.inlandWaters]: {
    threshold: 0.003,
    image: 'assets/images/textures/water.jpg',
    plantDensity: 0.05,
    colorFrom: [28, 78, 75],
    colorTo: [47, 131, 126],
  },
  [BiomeType.waterfront]: {
    threshold: 0.004,
    image: 'assets/images/textures/sand.webp',
    plantDensity: 0.05,
    colorFrom: [169, 141, 86],
    colorTo: [160, 129, 68],
  },
  [BiomeType.grass]: {
    threshold: 0.015,
    image: 'assets/images/textures/grass.webp',
    plantDensity: 0.1,
    colorFrom: [81, 105, 31],
    colorTo: [64, 84, 24],
  },
  [BiomeType.forest]: {
    threshold: 0.12,
    image: 'assets/images/textures/forest.jpg',
    plantDensity: 0.7,
    colorFrom: [49, 63, 28],
    colorTo: [39, 50, 22],
  },
  [BiomeType.mountain]: {
    threshold: 0.5,
    image: 'assets/images/textures/mountain.webp',
    plantDensity: 0.01,
    colorFrom: [84, 82, 63],
    colorTo: [67, 65, 50],
  },
  [BiomeType.snow]: {
    threshold: 1,
    image: 'assets/images/textures/snow.webp',
    plantDensity: 0,
    colorFrom: [161, 164, 164],
    colorTo: [212, 215, 215],
  },
} as const satisfies Record<BiomeType, Biome>;

export const getBiome = (type: BiomeType): Biome => BIOMES[type];

export const getBiomeFromHeight = (height: number, waterThreshold?: number): BiomeType => {
  if (waterThreshold && height < waterThreshold) return BiomeType.sea;
  for (const [key, biome] of Object.entries(BIOMES)) {
    if (height < biome.threshold) return key as BiomeType;
  }
  return BiomeType.snow;
};
